262	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
263	// querying the service's ListHarnesses and (best-effort) the harness registry.
264	// It is the production replacement for Runner.Capabilities.
265	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
266		if ctx == nil {
267			ctx = context.Background()
268		}
269		svc, err := NewServiceFromWorkDir(workDir)
270		if err != nil {
271			return nil, fmt.Errorf("agent: build service: %w", err)
272		}
273		infos, err := svc.ListHarnesses(ctx)
274		if err != nil {
275			return nil, fmt.Errorf("agent: list harnesses: %w", err)
276		}
277		var info *agentlib.HarnessInfo
278		for i := range infos {
279			if infos[i].Name == harnessName {
280				info = &infos[i]
281				break
282			}
283		}
284		if info == nil {
285			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
286		}
287	
288		// Pull binary and reasoning-level metadata from the local registry — the
289		// service does not expose these directly today.
290		registry := newHarnessRegistry()
291		harness, _ := registry.Get(harnessName)
292	
293		caps := &HarnessCapabilities{
294			Harness:             info.Name,
295			Available:           info.Available,
296			Binary:              harness.Binary,
297			Path:                info.Path,
298			Surface:             harness.Surface,
299			CostClass:           info.CostClass,
300			IsLocal:             info.IsLocal,
301			ExactPinSupport:     info.ExactPinSupport,
302			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
303			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
304		}
305		if len(info.SupportedReasoning) > 0 {
306			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
307		} else if len(harness.ReasoningLevels) > 0 {
308			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
309		}
310	
311		if harness.DefaultModel != "" {
312			caps.Model = harness.DefaultModel
313			caps.Models = []string{harness.DefaultModel}
314		}
315	
316		// Profile mappings come from the local model catalog because the service
317		// does not surface a per-tier resolution endpoint today.
318		if harness.Surface != "" {
319			cat := BuiltinCatalog
320			for _, profile := range []string{"cheap", "fast", "smart"} {
321				if m, ok := cat.Resolve(profile, harness.Surface); ok {
322					if caps.ProfileMappings == nil {
323						caps.ProfileMappings = make(map[string]string)
324					}
325					caps.ProfileMappings[profile] = m
326				}
327			}
328		}
329		return caps, nil
330	}
