743	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
744		summary := BenchmarkSummary{
745			TotalPrompts: len(result.Comparisons),
746		}
747		armStats := make(map[string]*BenchmarkArmSummary)
748		armOrder := make([]string, len(result.Arms))
749		for i, arm := range result.Arms {
750			label := arm.Label
751			armOrder[i] = label
752			armStats[label] = &BenchmarkArmSummary{Label: label}
753		}
754		for _, cmp := range result.Comparisons {
755			for _, arm := range cmp.Arms {
756				stats, ok := armStats[arm.Harness]
757				if !ok {
758					continue
759				}
760				if arm.ExitCode == 0 {
761					stats.Completed++
762				} else {
763					stats.Failed++
764				}
765				stats.TotalTokens += arm.Tokens
766				stats.TotalCostUSD += arm.CostUSD
767				stats.AvgDurationMS += arm.DurationMS
768			}
769		}
770		for _, label := range armOrder {
771			stats := armStats[label]
772			total := stats.Completed + stats.Failed
773			if total > 0 {
774				stats.AvgDurationMS = stats.AvgDurationMS / total
775			}
776			summary.Arms = append(summary.Arms, *stats)
777		}
778		return summary
779	}
